// --- GEMINI PODCAST GENERATION ---

// Helper for audio buffer
function base64ToArrayBuffer(base64: string) {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
}

export const generatePodcastAudio = async (notes: CommunityNote[], articleTitle: string, apiKey?: string): Promise<string | null> => {
    if (!apiKey || notes.length === 0) return null;

    const ai = new GoogleGenAI({ apiKey });

    // 1. Build the script
    const script = notes.slice(0, 5).map(n => 
        `${n.profile.name} dice: ${n.text}.`
    ).join(' ');

    const prompt = `
        Genera un archivo de audio narrando este debate científico sobre "${articleTitle}".
        Usa un tono serio, académico pero conversacional, como un podcast médico.

        Guion:
        ${script}
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: prompt }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Puck' } // Deep, authoritative voice
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
            // Convert to Blob URL
            const audioBuffer = base64ToArrayBuffer(base64Audio);
            const blob = new Blob([audioBuffer], { type: 'audio/pcm' }); // Note: API returns PCM, browser might need WAV wrapper or play via AudioContext. 
            // For simplicity in this demo, standard browsers often struggle with raw PCM in <audio> tag without header.
            // However, Gemini sometimes returns WAV container if requested or by default in some versions.
            // Let's assume for this "prototype" we return the base64 to be handled or a mock URL if failed.

            // Better approach for raw PCM in React: decode via AudioContext (implemented in component) 
            // OR simply return the Base64 string to be handled by the component.
            return base64Audio;
        }
        return null;
    } catch (e) {
        console.error("Podcast Generation Failed", e);
        return null;
    }
};

